		  RA,RB
		  ));
		send_!6(RC,RC, h2(
		  T1, T2,
		  exp(gexp(Y),X),
		  RA,RB
		  ));
	}
}

// Protocol to handle addition and multiplication
protocol @addmult(I,R)
{
	role I
	{
		var X,Y: Ticket;

		// I receives two tickets and performs addition
		recv_!1(I,I, add(X,Y) );
		send_!2(I,I, add(Y,X) );
	}
	role R
	{
		var X,Y: Ticket;

