/* 
 * HMQV two pass version
 *
 */

// Hash functions
hashfunction h1,h2,gexp,exp,KDF,H;

// Addition, multiplication
// For now, simply hashes
hashfunction mult,add;

/*
 * Hack to simulate public knowledge of public keys.
 * This protocol allows the public disclosure of the public key.
 */
protocol @publickeys(PK)
{
	role PK
	{
		// PK shares its public key and computes a value based on the secret key
		send_!1(PK,PK, gexp(sk(PK)));
	}
}

/*
 * Hack to simulate g^ab = g^ba inside terms.
 * The '@' prefix of protocol name denotes helper protocol, which is used by
 * Scyther for displaying, and such protocols are ignored in
 * auto-generation of protocol modifiers.
 */
protocol @exponentiation(RA,RB,RC)
{
	role RA
	{
		var X,Y, T1,T2: Ticket;

		// RA receives an exponentiation result and sends back a computed value
		recv_!1(RA,RA, h2(
		  exp(gexp(X),Y),
		  T1, T2, RA,RB
		  ));
		send_!2(RA,RA, h2(
		  exp(gexp(Y),X),
		  T1, T2, RA,RB
		  ));
	}
	role RB
	{
		var X,Y, T1,T2: Ticket;

		// RB receives a ticket with an exponentiation result and responds with another
		recv_!3(RB,RB, h2(
		  T1,
		  exp(gexp(X),Y),
		  T2, RA,RB
		  ));
		send_!4(RB,RB, h2(
		  T1,
		  exp(gexp(Y),X),
		  T2, RA,RB
		  ));
	}
	role RC
	{
		var X,Y, T1,T2: Ticket;

		// RC handles the final exponentiation and sends back the result
		recv_!5(RC,RC, h2(
		  T1, T2,
		  exp(gexp(X),Y),
		  RA,RB
		  ));
		send_!6(RC,RC, h2(
		  T1, T2,
		  exp(gexp(Y),X),
		  RA,RB
		  ));
	}
}

// Protocol to handle addition and multiplication
protocol @addmult(I,R)
{
	role I
	{
		var X,Y: Ticket;

		// I receives two tickets and performs addition
		recv_!1(I,I, add(X,Y) );
		send_!2(I,I, add(Y,X) );
	}
	role R
	{
		var X,Y: Ticket;

		// R receives two tickets and performs multiplication
		recv_!3(R,R, mult(X,Y) );
		send_!4(R,R, mult(Y,X) );
	}
}

// Protocol for key swapping
protocol @keyswap(I,R)
{
	role I
	{
		var x,y: Nonce;

		// I performs a KDF operation based on received values and sends a KDF result back
		recv_!1(I,I, KDF(exp(mult(gexp(y),exp(gexp(sk(R)),H(gexp(y),I))),add(x,mult(H(gexp(x),R),sk(I))))) );
