/* 
 * KEA+
 *
 * From "Security Analysis of KEA Authenticated Key Exchange Protocol"
 * Lauter, Mityagin, 2006.
 * 
 * We find no attacks in CK if only the ephemeral key is revealed.
 * We do find attacks for both roles in CK if the input to hash1 is revealed.
 */

// Hash functions
hashfunction h1,h2,g1,g2;

/*
 * Hack to gain equivalence of public keys to g^private.
 */
protocol @publickeys(RA,RB,RC)
{
	role RA
	{
		// RA sends its public key derived from its private key
		send_!1(RA,RA, g1(sk(RA)) );
	}
	role RB
	{
		// Special one to go into DH g2
		var T: Ticket;

		// RB receives a key encapsulated with a ticket, computes g2 and sends back
		recv_!2(RB,RB, g2(g1(T),sk(RB)) );
		send_!3(RB,RB, g2(pk(RB),T) );
	}
	role RC
	{
		// Special one to go into DH g2
		var T: Ticket;

		// RC receives a key encapsulated with a ticket and sends it back
		recv_!4(RC,RC, g2(pk(RC),T) );
		send_!5(RC,RC, g2(g1(T),sk(RC)) );
	}
}

/*
 * Hack to simulate g^ab = g^ba.
 * '@' prefix of protocol name denotes helper protocol, which is used by
 * Scyther for displaying, and such protocols are ignored in
 * auto-generation of protocol modifiers.
 */
protocol @exponentiation(RA,RB,RC)
{
	role RA
	{
		var alpha,beta, T1,T2: Ticket;

		// RA receives an exponentiated value and sends back a commuted value
		recv_!1(RA,RA, g2(g1(T1),T2) );
		send_!2(RA,RA, g2(g1(T2),T1) );
	}
	role RB
	{
		var T1,T2,T3: Ticket;

		// RB receives a hash input, computes the hash with T3 and sends a commuted value
		recv_!3(RB,RB, h1(g2(g1(T1),T2),T3,RC,RB) );
		send_!4(RB,RB, h1(g2(g1(T2),T1),T3,RC,RB) );
	}
	role RC
	{
		var T1,T2,T3: Ticket;

		// RC receives a hash input from RB and sends back a commuted hash
		recv_!5(RC,RC, h1(T3,g2(g1(T1),T2),RC,RA) );
		send_!6(RC,RC, h1(T3,g2(g1(T2),T1),RC,RA) );
	}
}

// The protocol description

protocol KEAplus(I,R)
{
	role I
	{
		fresh x: Nonce;
		var beta: Ticket;

		// I starts the protocol by sending a compromise message and its nonce x
		send_Compromise(I,I, x);
		send_1(I,R, g1(x) );

		// I waits for a ticket in response from R
		recv_2(R,I, beta );

		// I claims the session key SKR created via h1
		claim(I,SKR, h1(
		  g2(beta,sk(I)),
		  g2(pk(R),x),
		  I,R
		));
	}	

	role R
	{
		fresh y: Nonce;
		var alpha: Ticket;

		// R receives the message with I's nonce and sends its own compromise message
		recv_1(I,R, alpha );
		send_Compromise(R,R, y);
		send_2(R,I, g1(y) );

		// R claims the session key SKR created via h1
		claim(R,SKR, h1(
		  g2(pk(I),y),
		  g2(alpha,sk(R)),
		  I,R
		));
	}
}

